document.addEventListener("DOMContentLoaded",()=>{const expressionDisplay=document.getElementById("expressionDisplay");const resultDisplay=document.getElementById("resultDisplay");const angleModeButton=document.getElementById("angleMode");const historyList=document.getElementById("historyList");const copyButton=document.getElementById("copyResult");const clearHistoryButton=document.getElementById("clearHistory");const buttons=document.querySelectorAll(".calc-btn");let expression="";let displayExpression="";let angleMode="DEG";let lastResult="";let history=[];const updateScreen=(preview=true)=>{expressionDisplay.textContent=displayExpression||"0";if(!expression){resultDisplay.textContent="Ready";return;}
if(preview){try{const value=evaluateExpression(expression);if(Number.isFinite(value)){resultDisplay.textContent=`≈ ${formatNumber(value)}`;}}catch(error){resultDisplay.textContent="Keep typing...";}}};const appendValue=(value,label=value)=>{expression+=value;displayExpression+=label;updateScreen();};const appendFunction=(name)=>{const functionMap={sin:"sin(",cos:"cos(",tan:"tan(",log:"log10(",ln:"ln(",sqrt:"sqrt("};expression+=functionMap[name];displayExpression+=`${name}(`;updateScreen(false);};const calculate=()=>{if(!expression)return;try{const value=evaluateExpression(expression);if(!Number.isFinite(value))throw new Error("Invalid result");const formatted=formatNumber(value);lastResult=formatted;resultDisplay.textContent=formatted;addHistory(displayExpression,formatted);expression=String(value);displayExpression=formatted;}catch(error){resultDisplay.textContent="Math Error";}};const clearAll=()=>{expression="";displayExpression="";resultDisplay.textContent="Ready";expressionDisplay.textContent="0";};const deleteLast=()=>{if(!expression)return;const functionNames=["log10(","sqrt(","sin(","cos(","tan(","ln(","Math.PI","Math.E"];let removed=false;for(const fn of functionNames){if(expression.endsWith(fn)){expression=expression.slice(0,-fn.length);if(fn==="Math.PI")displayExpression=displayExpression.slice(0,-1);else if(fn==="Math.E")displayExpression=displayExpression.slice(0,-1);else displayExpression=displayExpression.slice(0,-fn.replace("10","").length);removed=true;break;}}
if(!removed){expression=expression.slice(0,-1);displayExpression=displayExpression.slice(0,-1);}
updateScreen();};const addHistory=(question,answer)=>{history.unshift({question,answer});history=history.slice(0,8);renderHistory();};const renderHistory=()=>{if(!history.length){historyList.innerHTML='<span class="empty-history">No history yet.</span>';return;}
historyList.innerHTML=history.map(item=>`
            <button class="history-item" type="button" data-answer="${item.answer}">
                <span>${escapeHtml(item.question)}</span>
                <strong>${escapeHtml(item.answer)}</strong>
            </button>
        `).join("");historyList.querySelectorAll(".history-item").forEach(item=>{item.addEventListener("click",()=>{expression=item.dataset.answer;displayExpression=item.dataset.answer;updateScreen(false);resultDisplay.textContent="History value loaded";});});};const performAction=(action)=>{switch(action){case"clear":clearAll();break;case"delete":deleteLast();break;case"calculate":calculate();break;case"square":expression+="**2";displayExpression+="²";updateScreen();break;case"inverse":expression=`1/(${expression || "0"})`;displayExpression=`1/(${displayExpression || "0"})`;updateScreen();break;case"factorial":expression+="!";displayExpression+="!";updateScreen();break;}};const evaluateExpression=(rawExpression)=>{let prepared=rawExpression.replace(/×/g,"*").replace(/÷/g,"/").replace(/\^/g,"**").replace(/(\d+(?:\.\d+)?)%/g,"($1/100)").replace(/(\d+)!/g,"factorial($1)");const allowed=/^[0-9+\-*/().,%!\sA-Za-z_*]+$/;if(!allowed.test(prepared))throw new Error("Invalid characters");return Function("sin","cos","tan","sqrt","log10","ln","factorial","Math",`"use strict"; return (${prepared});`)(trig("sin"),trig("cos"),trig("tan"),Math.sqrt,Math.log10,Math.log,factorial,Math);};const trig=(type)=>(value)=>{const number=angleMode==="DEG"?value*Math.PI/180:value;return Math[type](number);};const factorial=(value)=>{if(value<0||!Number.isInteger(value)||value>170)throw new Error("Invalid factorial");if(value===0||value===1)return 1;let result=1;for(let i=2;i<=value;i+=1)result*=i;return result;};const formatNumber=(value)=>{if(Math.abs(value)>=1e12||(Math.abs(value)<1e-7&&value!==0)){return value.toExponential(8).replace(/\.0+e/,"e");}
return Number.parseFloat(value.toFixed(10)).toString();};const escapeHtml=(text)=>String(text).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#039;");buttons.forEach(button=>{button.addEventListener("click",()=>{button.classList.add("pressed");setTimeout(()=>button.classList.remove("pressed"),120);if(button.dataset.action)performAction(button.dataset.action);else if(button.dataset.func)appendFunction(button.dataset.func);else if(button.dataset.value)appendValue(button.dataset.value,button.dataset.label||button.textContent.trim());});});angleModeButton.addEventListener("click",()=>{angleMode=angleMode==="DEG"?"RAD":"DEG";angleModeButton.textContent=angleMode;resultDisplay.textContent=`${angleMode} mode selected`;updateScreen(false);});copyButton.addEventListener("click",async()=>{const text=lastResult||resultDisplay.textContent;try{await navigator.clipboard.writeText(text);resultDisplay.textContent="Result copied";}catch(error){resultDisplay.textContent="Copy not available";}});clearHistoryButton.addEventListener("click",()=>{history=[];renderHistory();});document.addEventListener("keydown",(event)=>{const key=event.key;if(/^[0-9.+\-*/()%]$/.test(key))appendValue(key,key==="*"?"×":key==="/"?"÷":key);else if(key==="Enter")calculate();else if(key==="Backspace")deleteLast();else if(key==="Escape")clearAll();});updateScreen(false);});